 31	
 32	type NetworkAttachmentDefinitionFormProps = {
 33	  formData: NetworkAttachmentDefinitionKind;
 34	  onChange: (newFormData: NetworkAttachmentDefinitionKind) => void;
 35	};
 36	
 37	const NetworkAttachmentDefinitionForm: FC<NetworkAttachmentDefinitionFormProps> = ({
 38	  formData,
 39	  onChange,
 40	}) => {
 41	  const { t } = useNetworkingTranslation();
 42	  const navigate = useNavigate();
 43	  const [apiError, setError] = useState<Error>(null);
 44	  const [activeNamespace] = useActiveNamespace();
 45	  const namespace = ALL_NAMESPACES_KEY === activeNamespace ? DEFAULT_NAMESPACE : activeNamespace;
 46	
 47	  const methods = useForm<NetworkAttachmentDefinitionFormInput>({
 48	    defaultValues: fromNADObjToFormData(formData),
 49	  });
 50	
 51	  const {
 52	    formState: { isSubmitting, isValid },
 53	    handleSubmit,
 54	    register,
 55	    watch,
 56	  } = methods;
 57	
 58	  const formInput = watch();
 59	
 60	  useEffect(() => {
 61	    onChange(fromDataToNADObj(formInput, namespace));
 62	  }, [onChange, formInput, namespace]);
 63	
 64	  const onSubmit = (data: NetworkAttachmentDefinitionFormInput) => {
 65	    createNetAttachDef(data, namespace)
 66	      .then(() => {
 67	        navigate(resourcePathFromModel(NetworkAttachmentDefinitionModel, data?.name, namespace));
 68	      })
 69	      .catch((err) => {
 70	        setError(err);
 71	      });
 72	  };
 73	
 74	  return (
 75	    <Grid span={6}>
 76	      <PageSection variant={PageSectionVariants.light}>
 77	        <FormProvider {...methods}>
 78	          <Form onSubmit={handleSubmit(onSubmit)}>
 79	            <FormGroup
 80	              fieldId="name"
 81	              isRequired
 82	              label={t('Name')}
 83	              labelHelp={
 84	                <PopoverHelpIcon
 85	                  bodyContent={t(
 86	                    'Networks are not project-bound. Using the same name creates a shared NAD.',
 87	                  )}
 88	                />
 89	              }
 90	            >
 91	              <TextInput {...register('name', { required: true })} />
 92	            </FormGroup>
 93	            <FormGroup fieldId="description" label={t('Description')}>
 94	              <TextInput {...register('description')} />
 95	            </FormGroup>
 96	            <NetworkAttachmentDefinitionTypeSelect />
 97	            <NetworkTypeParameters />
 98	            {!isEmpty(apiError) && (
 99	              <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
100	                {apiError?.message}
101	              </Alert>
102	            )}
103	            <ActionGroup>
104	              <Button
105	                id="save-changes"
106	                isDisabled={!isValid || isSubmitting}
107	                isLoading={isSubmitting}
108	                type="submit"
109	                variant={ButtonVariant.primary}
110	              >
111	                {t('Create')}
112	              </Button>
113	              <Button
114	                id="cancel"
115	                onClick={() => navigate(-1)}
116	                type="reset"
117	                variant={ButtonVariant.secondary}
118	              >
119	                {t('Cancel')}
120	              </Button>
121	            </ActionGroup>
122	          </Form>
123	        </FormProvider>
124	      </PageSection>
125	    </Grid>
126	  );
127	};
128	
129	export default NetworkAttachmentDefinitionForm;

